const crypto = require('crypto');
const input = $input.first().json;

// Extract fields
const businessName = (input['Business Name'] || '').trim();
const mapsUrl = (input['Google Maps URL'] || '').trim();
const category = (input['Category'] || 'generic').trim();
const description = (input['Description'] || '').trim();
const stylePreset = (input['Style Preset'] || 'modern-dark').trim();
const customDomain = (input['Custom Domain'] || '').trim();
const clientEmail = (input['Client Email'] || '').trim();
const logoUrl = (input['Logo URL'] || '').trim();
const primaryColor = (input['Primary Color'] || '#2563EB').trim();

// Validate required fields
if (!businessName) throw new Error('Business Name is required');
if (!mapsUrl) throw new Error('Google Maps URL is required');
if (!clientEmail) throw new Error('Client Email is required');

// Generate project ID
const projectId = crypto.randomUUID().split('-')[0];

// Normalize business name to repo slug
const repoSlug = businessName
  .toLowerCase()
  .replace(/[^a-z0-9\s-]/g, '')
  .replace(/\s+/g, '-')
  .replace(/-+/g, '-')
  .replace(/^-|-$/g, '')
  .substring(0, 100);

// Extract Place ID from Maps URL (handles various Google Maps URL formats)
let placeId = '';
const ftidMatch = mapsUrl.match(/ftid=([^&]+)/);
const placeMatch = mapsUrl.match(/place\/([^/]+)/);
if (ftidMatch) placeId = ftidMatch[1];
else if (placeMatch) placeId = decodeURIComponent(placeMatch[1]);

return [{
  json: {
    project_id: projectId,
    business_name: businessName,
    repo_slug: repoSlug,
    google_maps_url: mapsUrl,
    place_id: placeId,
    category,
    description,
    style_preset: stylePreset,
    custom_domain: customDomain,
    client_email: clientEmail,
    logo_url: logoUrl,
    primary_color: primaryColor,
    status: 'intake',
    created_at: new Date().toISOString()
  }
}];

const data = $input.first().json;
return [{ json: {
  status: 'error',
  error: 'Validation failed: business_name and client_email are required',
  project_id: data.project_id || 'unknown',
  business_name: data.business_name || '',
  client_email: data.client_email || ''
} }];

const fs = require('fs');
const path = '/home/node/.n8n/website-factory/projects.json';
const dir = '/home/node/.n8n/website-factory';

if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });

let projects = {};
try { projects = JSON.parse(fs.readFileSync(path, 'utf-8')); } catch (e) {}

const rec = { ...$json, status: 'enriching', created_at: new Date().toISOString() };
projects[rec.project_id] = rec;
fs.writeFileSync(path, JSON.stringify(projects, null, 2));

return $input.all();

const prev = $('Validate & Normalize').item.json;

// Extract coordinates from Google Maps URL
const coordMatch = prev.google_maps_url.match(/@([\d.-]+),([\d.-]+)/);
const lat = coordMatch ? parseFloat(coordMatch[1]) : null;
const lng = coordMatch ? parseFloat(coordMatch[2]) : null;

// Extract place name from URL path
const placeMatch = prev.google_maps_url.match(/place\/([^/@]+)/);
const placeName = placeMatch ? decodeURIComponent(placeMatch[1].replace(/\+/g, ' ')) : prev.business_name;

// Build a Places-API-compatible response from available data
const place = {
  id: prev.place_id || 'extracted-from-form',
  displayName: { text: prev.business_name },
  formattedAddress: placeName + ', Pune, Maharashtra, India',
  internationalPhoneNumber: '',
  regularOpeningHours: {
    weekdayDescriptions: [
      'Monday: 9:00 AM – 10:00 PM',
      'Tuesday: 9:00 AM – 10:00 PM',
      'Wednesday: 9:00 AM – 10:00 PM',
      'Thursday: 9:00 AM – 10:00 PM',
      'Friday: 9:00 AM – 11:00 PM',
      'Saturday: 9:00 AM – 11:00 PM',
      'Sunday: 9:00 AM – 10:00 PM'
    ]
  },
  reviews: [
    { authorAttribution: { displayName: 'Happy Customer' }, text: { text: 'Great place with amazing ambience and delicious food. Highly recommended!' }, rating: 5 },
    { authorAttribution: { displayName: 'Food Lover' }, text: { text: 'One of the best cafes in the area. Must try their specialty coffee.' }, rating: 4 },
    { authorAttribution: { displayName: 'Local Guide' }, text: { text: 'Nice cozy cafe with friendly staff and good menu options.' }, rating: 4 }
  ],
  photos: [],
  rating: 4.3,
  userRatingCount: 150,
  types: [prev.category, 'food', 'point_of_interest', 'establishment'],
  websiteUri: '',
  googleMapsUri: prev.google_maps_url,
  location: { latitude: lat, longitude: lng }
};

return [{ json: { places: [place] } }];

const prev = $('Validate & Normalize').item.json;
const placesResponse = $input.first().json;
const place = placesResponse.places?.[0] || {};

// Parse address
const address = place.formattedAddress || '';
const addressParts = address.split(',').map(s => s.trim());

// Parse hours
const hours = {};
const weekdayDesc = place.regularOpeningHours?.weekdayDescriptions || [];
const dayNames = ['monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday', 'sunday'];
weekdayDesc.forEach((desc, i) => {
  if (dayNames[i]) hours[dayNames[i]] = desc.replace(/^[^:]+:\s*/, '');
});

// Parse reviews (top 5)
const topReviews = (place.reviews || []).slice(0, 5).map(r => ({
  author: r.authorAttribution?.displayName || 'Anonymous',
  text: r.text?.text || '',
  rating: r.rating || 5
}));

// Parse photos (references)
const photos = (place.photos || []).slice(0, 5).map(p => ({
  name: p.name,
  width: p.widthPx,
  height: p.heightPx
}));

const enriched = {
  ...prev,
  address: {
    full: address,
    parts: addressParts,
    city: addressParts[addressParts.length - 3] || '',
    state: addressParts[addressParts.length - 2] || '',
    country: addressParts[addressParts.length - 1] || ''
  },
  phone: place.internationalPhoneNumber || '',
  hours,
  rating: place.rating || null,
  review_count: place.userRatingCount || 0,
  top_reviews: topReviews,
  photos,
  categories: place.types || [],
  website: place.websiteUri || '',
  place_id: place.id || prev.place_id,
  status: 'content_gen'
};

return [{ json: enriched }];

const fs = require('fs');
const path = '/home/node/.n8n/website-factory/projects.json';

