const data = $input.first().json;

const hoursSummary = Object.entries(data.hours || {})
  .map(([day, time]) => `${day}: ${time}`)
  .join(', ');

const reviewsText = (data.top_reviews || [])
  .map(r => `- "${r.text.substring(0, 200)}" — ${r.author} (${r.rating}★)`)
