const systemPrompt = `You are a professional web copywriter who specializes in creating compelling website content for local businesses. You write clear, engaging, and conversion-focused copy.

RULES:
- Only use facts provided in the business data. NEVER invent or hallucinate details.
- Write in a warm, professional tone appropriate for the business category.
- Keep copy concise — website visitors scan, they don't read essays.
- Include specific details (address, phone, hours) when available.
- Optimize all text for SEO naturally — no keyword stuffing.
- For testimonials, lightly polish the original reviews for grammar and clarity, but preserve the authentic voice.
- Return ONLY valid JSON. No markdown, no explanation, no code fences.`;

const userPrompt = `Generate complete website content for:

BUSINESS DATA:
- Name: ${data.business_name}
- Category: ${data.category}
- Description: ${data.description || 'Not provided'}
- Address: ${data.address?.full || 'Not provided'}
- Phone: ${data.phone || 'Not provided'}
- Rating: ${data.rating || 'N/A'} (${data.review_count || 0} reviews)
- Hours: ${hoursSummary || 'Not provided'}
- Reviews:
${reviewsText || '  None available'}

STYLE: ${data.style_preset}, PRIMARY COLOR: ${data.primary_color}

Return JSON with these exact keys: business_name, headline, headline_alternates (array of 2), phone, email, address, google_maps_url, primary_color, about (object: title, body), services (array of 3-6: title, description, icon emoji), faq (array of 5-8: question, answer), testimonials (array of 3-5: author, quote, rating), hours (object: monday-sunday), cta (object: primary_text, primary_url, secondary_text, secondary_url), seo (object: title max 60 chars, description max 160 chars, keywords), nav_items (array of 4-6 strings), features (array of exactly 3: title, subtitle, icon emoji), amenities (array of 3-5: label, icon emoji).`;

return [{ json: { ...data, system_prompt: systemPrompt, user_prompt: userPrompt } }];

const prev = $('Build Content Prompt').item.json;
const response = $input.first().json;

// Extract text from Claude response
let contentText = '';
if (response.content && response.content.length > 0) {
  contentText = response.content[0].text || '';
}

// Try to parse JSON from the response (handle potential markdown fences)
let cleanedText = contentText.trim();
if (cleanedText.startsWith('```')) {
  cleanedText = cleanedText.replace(/^```[a-z]*\n?/, '').replace(/\n?```$/, '');
}

let aiContent;
try {
  aiContent = JSON.parse(cleanedText);
} catch (e) {
