  ...prev,
  ai_content: aiContent,
  status: 'mockup_gen'
} }];

const data = $input.first().json;
const content = data.ai_content;

const categoryDescriptions = {
  restaurant: 'elegant restaurant interior with warm ambient lighting and well-set tables',
  salon: 'modern beauty salon interior with stylish chairs, mirrors, and professional lighting',
  agency: 'sleek modern office space with glass walls and city views',
  multiplex: 'grand cinema multiplex exterior at night with bright marquee lights and movie posters',
  gym: 'modern gym interior with professional equipment and energetic atmosphere',
  clinic: 'clean, bright medical clinic reception area with modern furniture',
  generic: 'professional modern business storefront with clean signage'
};

const navItems = (content.nav_items || ['Home', 'About', 'Services', 'Contact']).join(', ');
const features = (content.features || []).map((f, i) =>
  `Card ${i+1}: Icon "${f.icon}", title "${f.title}", subtitle "${f.subtitle}"`
).join('; ');
const amenities = (content.amenities || []).map(a =>
  `${a.icon} "${a.label}"`
).join(', ');

const imagePrompt = `Design a professional, polished website landing page screenshot for "${content.business_name}", a ${data.category} business in ${data.address?.city || 'the local area'}.

LAYOUT (top to bottom):
1. NAVIGATION BAR: Logo/name left, menu items: ${navItems}, CTA button "${content.cta?.primary_text || 'Get Started'}" right
2. HERO SECTION (60% viewport): Photorealistic background of a ${categoryDescriptions[data.category] || categoryDescriptions.generic}, dark gradient overlay, heading "${content.business_name}", tagline "${content.headline}", two CTA buttons
3. FEATURES (3 cards): ${features}
4. ADDRESS BAR: "${content.address || data.address?.full || ''}"
5. AMENITY BADGES: ${amenities}

STYLE: ${data.style_preset} palette, primary color ${data.primary_color}, modern sans-serif, premium feel, generous whitespace, subtle shadows on cards.

CRITICAL: Must look like a real website screenshot. Realistic readable text. Proper visual hierarchy. Match quality of premium Wix/Squarespace templates. No browser chrome. Portrait 1024x1792.`;

return [{ json: { ...data, image_prompt: imagePrompt } }];

