`;

const cmsPath = `${projectDir}/config.yml`;
fs.writeFileSync(cmsPath, cmsConfig);

return [{ json: {
  ...data,
  mockup_path: mockupPath,
  content_path: contentPath,
  cms_config_path: cmsPath,
  project_dir: projectDir,
  github_owner: githubOwner,
  status: 'site_building'
} }];

const fs = require('fs');
const path = '/home/node/.n8n/website-factory/projects.json';

let projects = {};
try { projects = JSON.parse(fs.readFileSync(path, 'utf-8')); } catch (e) {}

const pid = $json.project_id;
if (projects[pid]) {
  projects[pid].status = 'site_building';
  projects[pid].ai_content = JSON.stringify($json.ai_content || {}).substring(0, 5000);
  projects[pid].mockup_image_path = $json.mockup_path;
  projects[pid].updated_at = new Date().toISOString();
  fs.writeFileSync(path, JSON.stringify(projects, null, 2));
