return $input.all();

const { execSync } = require('child_process');
const fs = require('fs');

const data = $input.first().json;
const projectId = data.project_id;
const projectDir = data.project_dir || `/tmp/website-factory/${projectId}`;
const siteDir = `${projectDir}/site`;

// 1. Clone template repo
try {
  if (fs.existsSync(siteDir)) {
    execSync(`rm -rf ${siteDir}`, { encoding: 'utf-8' });
  }
  execSync(`git clone --depth 1 https://github.com/tech-sumit/website-factory-base.git ${siteDir}`, { timeout: 60000, encoding: 'utf-8' });
  // Remove .git so we can re-init later
  execSync(`rm -rf ${siteDir}/.git`, { encoding: 'utf-8' });
  // Init fresh git repo
  execSync(`cd ${siteDir} && git init && git checkout -b main`, { encoding: 'utf-8' });
} catch (e) {
  throw new Error('Failed to clone template repo: ' + e.message);
}

// 2. Copy design-spec.md and content.json into site dir
const designSpecPath = `${projectDir}/design-spec.md`;
const contentPath = `${projectDir}/content.json`;

if (fs.existsSync(designSpecPath)) {
  fs.copyFileSync(designSpecPath, `${siteDir}/design-spec.md`);
}
if (fs.existsSync(contentPath)) {
  // Copy as content/site.json for the Astro site
  fs.mkdirSync(`${siteDir}/content`, { recursive: true });
  fs.copyFileSync(contentPath, `${siteDir}/content/site.json`);
}

// 3. Copy CMS config.yml into public/admin/
const cmsConfigPath = data.cms_config_path || `${projectDir}/config.yml`;
if (fs.existsSync(cmsConfigPath)) {
  fs.mkdirSync(`${siteDir}/public/admin`, { recursive: true });
  fs.copyFileSync(cmsConfigPath, `${siteDir}/public/admin/config.yml`);
  // Create admin index.html for Decap CMS
  const adminHtml = '<!doctype html>\n<html>\n<head>\n  <meta charset="utf-8" />\n  <meta name="viewport" content="width=device-width, initial-scale=1.0" />\n  <title>Content Manager</title>\n  <script src="https://unpkg.com/decap-cms@^3.0.0/dist/decap-cms.js"></script>\n</head>\n<body></body>\n</html>';
  fs.writeFileSync(`${siteDir}/public/admin/index.html`, adminHtml);
}

// 4. Read design spec and content to build prompt
let designSpec = '';
try { designSpec = fs.readFileSync(designSpecPath, 'utf-8'); } catch(e) {}

let contentJson = '{}';
try { contentJson = fs.readFileSync(contentPath, 'utf-8'); } catch(e) {}

// 5. Build comprehensive prompt for Claude API
const fileList = [
  'src/pages/index.astro',
  'src/components/Navbar.astro',
  'src/components/Hero.astro',
  'src/components/Features.astro',
  'src/components/About.astro',
  'src/components/Services.astro',
  'src/components/Testimonials.astro',
  'src/components/FAQ.astro',
  'src/components/Contact.astro',
  'src/components/Footer.astro'
];

const userPrompt = `Generate an Astro website based on the following design specification and content data.

## Design Specification
${designSpec}

## Content Data (site.json)
${contentJson}

## Files to Generate
Create these files:
${fileList.map(f => '- ' + f).join('\n')}

## Rules
- Use Tailwind CSS for all styling (already configured in the template)
- Read content from the site.json file using: import siteData from '../../content/site.json' (adjust relative path per file depth)
- Mobile-first responsive design
- Fully accessible (ARIA labels, semantic HTML, proper heading hierarchy)
- Each component should be self-contained with its own section styling
- index.astro should import and compose all components
- Use the primary_color from site.json for brand accents
- Include smooth scroll behavior for anchor links
- Add subtle animations with Tailwind (hover effects, transitions)

## Response Format
Return ONLY a JSON object where keys are file paths (relative to project root) and values are the complete file contents. No explanation, no markdown code fences, just pure JSON.

Example:
{"src/pages/index.astro": "---\nimport Navbar from ...\n---\n<html>...</html>", "src/components/Navbar.astro": "---\nimport siteData from ...\n---\n<nav>...</nav>"}`;

return [{ json: {
  ...data,
  site_dir: siteDir,
  claude_prompt: userPrompt,
  files_to_generate: fileList,
  status: 'site_building'
} }];

const fs = require('fs');
const path = require('path');

const prev = $('Run Claude Code - Generate Site').item.json;
const response = $input.first().json;
const siteDir = prev.site_dir;

// Extract text from Claude response
let contentText = '';
if (response.content && response.content.length > 0) {
  contentText = response.content[0].text || '';
}

// Clean potential markdown fences
let cleanedText = contentText.trim();
if (cleanedText.startsWith('```')) {
  cleanedText = cleanedText.replace(/^```[a-z]*\n?/, '').replace(/\n?```$/, '');
}

// Parse the JSON of file paths -> contents
let files;
try {
  files = JSON.parse(cleanedText);
} catch (e) {
  throw new Error('Failed to parse Claude API response as JSON: ' + e.message + '\nResponse preview: ' + cleanedText.substring(0, 500));
}

if (typeof files !== 'object' || Array.isArray(files)) {
  throw new Error('Expected JSON object with file paths as keys, got: ' + typeof files);
}

// Write each file
let componentCount = 0;
const writtenFiles = [];

for (const [filePath, content] of Object.entries(files)) {
  // Security: prevent path traversal
  const normalizedPath = path.normalize(filePath);
  if (normalizedPath.startsWith('..') || normalizedPath.startsWith('/')) {
    continue;
  }

  const fullPath = path.join(siteDir, normalizedPath);
  const dir = path.dirname(fullPath);

  fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(fullPath, content, 'utf-8');
  writtenFiles.push(normalizedPath);

  if (normalizedPath.includes('src/components/') && normalizedPath.endsWith('.astro')) {
    componentCount++;
  }
}

return [{ json: {
  ...prev,
  component_count: componentCount,
  written_files: writtenFiles,
  files_written_count: writtenFiles.length,
  site_dir: siteDir,
  status: 'site_building'
} }];

const data = $input.first().json;
const fs = require('fs');
const siteDir = data.site_dir;

// Validate critical files
const requiredFiles = [
  'src/pages/index.astro',
  'public/admin/index.html',
  'public/admin/config.yml',
  'package.json',
  'content/site.json'
];

const missing = requiredFiles.filter(f => !fs.existsSync(`${siteDir}/${f}`));
if (missing.length > 0) {
  throw new Error(`Build validation failed — missing files: ${missing.join(', ')}`);
}

// Count components
let componentCount = data.component_count || 0;
try {
  componentCount = fs.readdirSync(`${siteDir}/src/components`)
    .filter(f => f.endsWith('.astro')).length;
} catch(e) {}

if (componentCount < 3) {
  throw new Error(`Only ${componentCount} components generated, expected 5+`);
}

return [{ json: {
  ...data,
  component_count: componentCount,
  site_dir: siteDir,
  status: 'pushing'
} }];

const { execSync } = require('child_process');
const siteDir = $('Validate Build Output').item.json.site_dir;
const githubOwner = $('Validate Build Output').item.json.github_owner;
const repoSlug = $('Validate Build Output').item.json.repo_slug;
const githubToken = $env.GITHUB_TOKEN;
const cmd = `cd ${siteDir} && git remote remove origin 2>/dev/null || true && git remote add origin https://${githubToken}@github.com/${githubOwner}/${repoSlug}.git && git add -A && git commit -m "Initial site generation by Website Factory" --author="Website Factory <bot@panditai.org>" && git push -u origin main`;
execSync(cmd, { timeout: 60000 });
return $input.all();

const data = $('Validate Build Output').item.json;
const verifyResponse = $input.first().json;
const isLive = verifyResponse.statusCode === 200 || verifyResponse.statusCode === 304;

const pagesUrl = `https://${data.github_owner}.github.io/${data.repo_slug}/`;
const cmsUrl = `${pagesUrl}admin/`;
const repoUrl = `https://github.com/${data.github_owner}/${data.repo_slug}`;

return [{ json: {
  project_id: data.project_id,
  business_name: data.business_name,
  repo_slug: data.repo_slug,
  category: data.category,
  client_email: data.client_email,
  github_owner: data.github_owner,
  pages_url: pagesUrl,
  cms_url: cmsUrl,
  repo_url: repoUrl,
  custom_domain: data.custom_domain,
  component_count: data.component_count,
  is_live: isLive,
  status: isLive ? 'live' : 'deploying',
  published_at: isLive ? new Date().toISOString() : null
} }];

const fs = require('fs');
const path = '/home/node/.n8n/website-factory/projects.json';

let projects = {};
try { projects = JSON.parse(fs.readFileSync(path, 'utf-8')); } catch (e) {}

const pid = $json.project_id;
