const error = $input.first().json;

// Map the failed node to a pipeline stage
const failedNode = error.execution?.lastNodeExecuted || 'unknown';
const nodeStageMap = {
  'Google Places - Text Search': 'enriching',
  'Parse Places Data': 'enriching',
  'Claude API - Generate Content': 'content_gen',
  'Parse Content Response': 'content_gen',
  'Build Image Prompt': 'mockup_gen',
