  'Validate Build Output': 'site_building',
  'Create GitHub Repo': 'pushing',
  'Git Push to Repo': 'pushing',
  'Enable GitHub Pages': 'pushing'
};

const stage = nodeStageMap[failedNode] || 'unknown';
const errorMessage = error.execution?.error?.message || error.message || 'Unknown error';

// Try to extract project_id from the execution data
let projectId = 'unknown';
try {
  const nodeData = error.execution?.data?.resultData?.runData;
  if (nodeData && nodeData['Validate & Normalize']) {
    projectId = nodeData['Validate & Normalize'][0]?.data?.main?.[0]?.[0]?.json?.project_id || 'unknown';
  }
} catch(e) {}

